        semantics,
        includesNodeWith(
          label: 'Start auto-explore',
          actions: <SemanticsAction>[SemanticsAction.tap],
          flags: <SemanticsFlag>[SemanticsFlag.isButton],
        ),
      );
    });
  });
}

